use crate::graph::test_support::*;
use crate::graph::Direction;
use crate::model::{Edge, Node, NodeType, RelationType};

#[test]
fn upsert_node_reports_created_then_reinforced() {
    let s = store();
    let node = Node::new("artifact:a", NodeType::Artifact, "a", NOW);
    assert!(s.upsert_node(&node).unwrap()); // created
    assert!(!s.upsert_node(&node).unwrap()); // reinforced, not created
    assert!(s.get_node("artifact:a").unwrap().is_some());
}

#[test]
fn upsert_edge_reinforces_weight_on_conflict() {
    let s = store();
    add_node(&s, "artifact:a", NodeType::Artifact, "a", NOW);
    add_node(&s, "artifact:b", NodeType::Artifact, "b", NOW);
    let e = raw_edge(
        "artifact:a",
        "artifact:b",
        RelationType::Modified,
        0.5,
        48.0,
        NOW,
    );
    assert!(s.upsert_edge(&e).unwrap()); // created
    assert!(!s.upsert_edge(&e).unwrap()); // reinforced

    let sub = s
        .traverse(&["artifact:a".into()], Direction::Outgoing, 1, 0.0, NOW)
        .unwrap();
    let edge = sub
        .edges
        .iter()
        .find(|x| x.target_id == "artifact:b")
        .unwrap();
    assert!((edge.base_weight - 0.55).abs() < 1e-9);
}

#[test]
fn replace_structure_rolls_back_when_a_new_edge_is_invalid() {
    // A partial replacement would erase valid structure and leave newly
    // inserted nodes behind; one transaction must preserve the old snapshot.
    let s = store();
    let owner = Node::new("artifact:a", NodeType::Artifact, "a", NOW);
    let original = Node::new("symbol:a:original", NodeType::Symbol, "original", NOW);
    let original_edge = Edge::new(
        "artifact:a",
        "symbol:a:original",
        RelationType::Contains,
        NOW,
    );
    s.replace_structure(
        "artifact:a",
        &[owner.clone(), original],
        &[original_edge],
        &[],
    )
    .unwrap();

    let replacement = Node::new("symbol:a:new", NodeType::Symbol, "new", NOW);
    let invalid_edge = Edge::new(
        "artifact:a",
        "symbol:a:missing",
        RelationType::Contains,
        NOW,
    );
    assert!(s
        .replace_structure("artifact:a", &[owner, replacement], &[invalid_edge], &[],)
        .is_err());

    assert!(s.get_node("symbol:a:original").unwrap().is_some());
    assert!(s.get_node("symbol:a:new").unwrap().is_none());
    let current = s
        .traverse(&["artifact:a".into()], Direction::Outgoing, 1, 0.0, NOW)
        .unwrap();
    assert!(current
        .edges
        .iter()
        .any(|edge| edge.target_id == "symbol:a:original"));
}

#[test]
fn replace_structure_retracts_legacy_unowned_calls() {
    // Pre-ADR-0007 calls have no owner; the first authoritative ingest must
    // claim and diff them so a removed call does not survive migration.
    let s = store();
    let owner = Node::new("artifact:a", NodeType::Artifact, "a", NOW);
    let caller = Node::new("symbol:a:caller", NodeType::Symbol, "caller", NOW);
    let removed = Node::new("symbol:a:removed", NodeType::Symbol, "removed", NOW);
    for node in [&owner, &caller, &removed] {
        s.upsert_node(node).unwrap();
    }
    for edge in [
        Edge::new("artifact:a", "symbol:a:caller", RelationType::Contains, NOW),
        Edge::new(
            "artifact:a",
            "symbol:a:removed",
            RelationType::Contains,
            NOW,
        ),
        Edge::new(
            "symbol:a:caller",
            "symbol:a:removed",
            RelationType::Calls,
            NOW,
        ),
    ] {
        s.upsert_edge(&edge).unwrap();
    }

    let current_contains = Edge::new("artifact:a", "symbol:a:caller", RelationType::Contains, NOW);
    s.replace_structure("artifact:a", &[owner, caller], &[current_contains], &[])
        .unwrap();

    assert!(s.get_node("symbol:a:removed").unwrap().is_none());
    let current = s
        .traverse(
            &["symbol:a:caller".into()],
            Direction::Outgoing,
            1,
            0.0,
            NOW,
        )
        .unwrap();
    assert!(!current
        .edges
        .iter()
        .any(|edge| edge.target_id == "symbol:a:removed"));
}

#[test]
fn replace_structure_rejects_structural_owner_transfer() {
    let s = store();
    let owner = Node::new("artifact:a", NodeType::Artifact, "a", NOW);
    let symbol = Node::new("symbol:a:f", NodeType::Symbol, "f", NOW);
    let contains = Edge::new("artifact:a", "symbol:a:f", RelationType::Contains, NOW);
    s.replace_structure(
        "artifact:a",
        &[owner.clone(), symbol.clone()],
        std::slice::from_ref(&contains),
        &[],
    )
    .unwrap();
    s.conn
        .execute(
            "UPDATE edges SET owner_id = 'artifact:other' WHERE relation = 'contains'",
            [],
        )
        .unwrap();

    let error = s
        .replace_structure("artifact:a", &[owner, symbol], &[contains], &[])
        .unwrap_err();
    assert!(error.to_string().contains("owned by artifact:other"));
    let owner_id: String = s
        .conn
        .query_row("SELECT owner_id FROM edges", [], |row| row.get(0))
        .unwrap();
    assert_eq!(owner_id, "artifact:other");
}
